statements.select:

/* WHERE 1=1 AND SHOWMENU = '1'*/
SELECT * FROM AMFUNCM
ORDER BY SYSID, MODULES, SUBMODULES,PRGORDER


/* 'TEACHER */
WITH WT1 AS (SELECT TEACHERNAME,IDNO,ACCOUNT,UNITCODE,convert(varchar(4),YEAR(GETDATE())) YEARS FROM TEACHER t)
/* 'MeetingAttend */
,WM1 AS ( SELECT a.TeacherAccount ACCOUNT,b.MeetingType,a.Attend, a.TestPassed,b.CreatedUnit
FROM MeetingAttend a JOIN Meeting b ON a.MeetingSeq=b.Seq
WHERE b.Year=YEAR(GETDATE()) )
/* 'TransData_D_Class */
,WTD AS ( SELECT a.TeacherID,a.TeacherName,a.PlanCode,a.UnitCode,a.UnitName,a.PlanID
/*--,dbo.FN_GET_ACTUALYEAR(SUBSTRING(a.ClassDateS,5,3),SUBSTRING(a.ClassDateS,11,2)) YEARS*/
,a.SchoolName,a.ClassName,a.TrainingDateS,a.TrainingDateE,a.ClassDateS,a.ClassDateE
,a.JobAbilityCode,a.CourseUnitCode,a.TeachHours,a.TeachNum,a.QuestLink
,CONVERT(NVARCHAR, a.UpdatedDatetime, 120) UpdatedDatetime
FROM TransData_D_Class a
WHERE dbo.FN_GET_ACTUALYEAR(SUBSTRING(a.ClassDateS,5,3),SUBSTRING(a.ClassDateS,11,2))=YEAR(GETDATE()) )
/* 'TransData_S_Class */
,WTS AS ( SELECT TeacherID,TeacherName,ClassName,CourseUnitCode,ClassDateS,TrainingTimeS
,CONVERT(NVARCHAR, MAX(UpdatedDatetime), 120) AS UpdatedDatetime
,MAX(PlanCode) PlanCode,MAX(TrainID) TrainID,MIN(ClassID) ClassID,MAX(UnitCode) UnitCode,MAX(UnitName) UnitName
,MAX(JoinCompany) JoinCompany,MAX(TrainingUnit) TrainingUnit
,MAX(TrainingTimeE) TrainingTimeE,MAX(ClassDateE) ClassDateE
,MAX(JobAbilityCode) JobAbilityCode,MAX(TeachHours) TeachHours,MAX(TeachNum) TeachNum,MAX(QuestLink) QuestLink
FROM TransData_S_Class
WHERE Year=YEAR(GETDATE())
GROUP BY TeacherID,TeacherName,ClassName,CourseUnitCode,ClassDateS,TrainingTimeS )
/* 'TransData_D_Satisfy */
,WTDSA AS ( select a.TeacherID,COUNT(CASE WHEN (CAST(0 AS FLOAT)+CAST(ISNULL(ds.Q1,'0') AS FLOAT)+CAST(ISNULL(ds.Q2,'0') AS FLOAT)+CAST(ISNULL(ds.Q3,'0') AS FLOAT)+CAST(ISNULL(ds.Q4,'0') AS FLOAT)+CAST(ISNULL(ds.Q5,'0') AS FLOAT)
 +CAST(ISNULL(ds.Q6,'0') AS FLOAT)+CAST(ISNULL(ds.Q7,'0') AS FLOAT)+CAST(ISNULL(ds.Q8,'0') AS FLOAT)+CAST(ISNULL(ds.Q9,'0') AS FLOAT)+CAST(ISNULL(ds.Q10,'0') AS FLOAT)
 +CAST(ISNULL(ds.Q11,'0') AS FLOAT) )/11>=4 THEN 1 END) SatisfyQ,COUNT(1) StudCNT
 FROM TransData_D_Class a
 JOIN TransData_D_Satisfy ds on ds.Year=a.Year AND ds.PlanID=a.PlanID AND ds.CourseUnitCode=a.CourseUnitCode AND ds.TeacherID=a.TeacherID
 WHERE dbo.FN_GET_ACTUALYEAR(SUBSTRING(a.ClassDateS,5,3),SUBSTRING(a.ClassDateS,11,2))=YEAR(GETDATE())
 GROUP BY a.TeacherID )
,WTDS AS ( SELECT a.TeacherID,CASE WHEN a.StudCNT >0 THEN CEILING(1.0*a.SatisfyQ/a.StudCNT*100) END Satisfy FROM WTDSA a)
/* 'TransData_S_Satisfy */
,WTSSA AS ( select b.TeacherID,COUNT(CASE WHEN (CAST(0 AS FLOAT)+CAST(ISNULL(ds.Q1,'0') AS FLOAT)+CAST(ISNULL(ds.Q2,'0') AS FLOAT)+CAST(ISNULL(ds.Q3,'0') AS FLOAT)+CAST(ISNULL(ds.Q4,'0') AS FLOAT)+CAST(ISNULL(ds.Q5,'0') AS FLOAT)
 +CAST(ISNULL(ds.Q6,'0') AS FLOAT)+CAST(ISNULL(ds.Q7,'0') AS FLOAT)+CAST(ISNULL(ds.Q8,'0') AS FLOAT)+CAST(ISNULL(ds.Q9,'0') AS FLOAT)+CAST(ISNULL(ds.Q10,'0') AS FLOAT)
 +CAST(ISNULL(ds.Q11,'0') AS FLOAT))/11>=4 THEN 1 END) SatisfyQ,COUNT(1) StudCNT
 FROM TransData_S_Satisfy ds
 JOIN TransData_S_Class b on ds.Year=b.Year AND ds.TrainID=b.TrainID AND ds.ClassID=b.ClassID AND ds.CourseUnitCode=b.CourseUnitCode AND ds.TeacherID=b.TeacherID
 WHERE b.Year=YEAR(GETDATE())
 GROUP BY b.TeacherID )
,WTSS AS ( SELECT a.TeacherID,CASE WHEN a.StudCNT >0 THEN CEILING(1.0*a.SatisfyQ/a.StudCNT*100) END Satisfy FROM WTSSA a)
/* 'TransData_D_Satisfy & TransData_S_Satisfy */
,WTDSA2 AS ( SELECT c.TeacherID,SUM(SatisfyQ) SatisfyQ,SUM(StudCNT) StudCNT
FROM (SELECT TeacherID,SatisfyQ,StudCNT FROM WTDSA 
UNION ALL SELECT TeacherID,SatisfyQ,StudCNT FROM WTSSA) c
GROUP BY c.TeacherID )
,WTDS2 AS ( SELECT a.TeacherID,CASE WHEN a.StudCNT >0 THEN CEILING(1.0*a.SatisfyQ/a.StudCNT*100) END Satisfy FROM WTDSA2 a)

/*--回流訓-是否出席 objSheet.Column(16).Width = 10;*/
SELECT t.TEACHERNAME,t.IDNO,t.ACCOUNT,t.UNITCODE,t.YEARS
/*--回流訓-是否出席 objSheet.Column(16).Width = 10;*/
,(SELECT COUNT(CASE WHEN a.MeetingType='1' AND a.Attend='Y' THEN 1 END) FROM WM1 a WHERE a.ACCOUNT=t.ACCOUNT) MT1_ATTENDANCE_CNT
/*--回流訓-筆試測驗 objSheet.Column(17).Width = 10; MT1_WRITTEN_EXAM*/
,(SELECT COUNT(CASE WHEN a.MeetingType='1' AND a.Attend='Y' AND a.TestPassed='Y' THEN 1 END) FROM WM1 a WHERE a.ACCOUNT=t.ACCOUNT) MT1_WRITTEN_EXAM
/*--回流訓-結果 objSheet.Column(18).Width = 10; MT1_RESULTS*/
,(SELECT COUNT(CASE WHEN a.MeetingType='1' AND a.Attend='Y' AND a.TestPassed='Y' THEN 1 END) FROM WM1 a WHERE a.ACCOUNT=t.ACCOUNT) MT1_RESULTS
/*--授課時數-補助大專校院辦理就業學程計畫-DC objSheet.Column(19).Width = 10; THOURS_TRANSDATA_D_DC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTD a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='DC') THOURS_TRANSDATA_D_DC
/*--授課時數-補助大專校院辦理就業學程計畫-BC objSheet.Column(20).Width = 10; THOURS_TRANSDATA_D_BC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTD a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='BC') THOURS_TRANSDATA_D_BC
/*--授課時數-補助大專校院辦理就業學程計畫-KC objSheet.Column(21).Width = 10; THOURS_TRANSDATA_D_KC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTD a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='KC') THOURS_TRANSDATA_D_KC
/*--授課時數-小型企業人力提升計畫-DC objSheet.Column(22).Width = 10; THOURS_TRANSDATA_S_DC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTS a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='DC') THOURS_TRANSDATA_S_DC
/*--授課時數-小型企業人力提升計畫-BC objSheet.Column(23).Width = 10; THOURS_TRANSDATA_S_BC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTS a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='BC') THOURS_TRANSDATA_S_BC
/*--授課時數-小型企業人力提升計畫-KC objSheet.Column(24).Width = 10; THOURS_TRANSDATA_S_KC*/
,(SELECT SUM(TeachHours) TeachHours FROM WTS a WHERE a.TeacherID=t.IDNO and a.JobAbilityCode='KC') THOURS_TRANSDATA_S_KC
/*--授課時數-授課總時數 objSheet.Column(25).Width = 10; --THOURS_TRANSDATA_D_TOTAL  --THOURS_TRANSDATA_S_TOTAL*/
,(SELECT SUM(TeachHours) TeachHours FROM WTD a WHERE a.TeacherID=t.IDNO) THOURS_TRANSDATA_D_TOTAL
,(SELECT SUM(TeachHours) TeachHours FROM WTS a WHERE a.TeacherID=t.IDNO) THOURS_TRANSDATA_S_TOTAL
/*--授課滿意度達70%以上對象表示滿意情形-補助大專校院辦理就業學程計畫 objSheet.Column(26).Width = 10; SATISFY_TRANSDATA_D*/
,(SELECT Satisfy FROM WTDS a WHERE a.TeacherID=t.IDNO) SATISFY_TRANSDATA_D
/*--授課滿意度達70%以上對象表示滿意情形-小型企業人力提升計畫 objSheet.Column(27).Width = 10; SATISFY_TRANSDATA_S*/
,(SELECT Satisfy FROM WTSS a WHERE a.TeacherID=t.IDNO) SATISFY_TRANSDATA_S
/*--授課滿意度達70%以上對象表示滿意情形-整體 objSheet.Column(28).Width = 10; NULL (A+B)/2*/
,(SELECT Satisfy FROM WTDS2 a WHERE a.TeacherID=t.IDNO) SATISFY_TRANSDATA_DS
/*--出席共識聯繫會議次數 objSheet.Column(29).Width = 10; MEETING_TIMES*/
,(SELECT COUNT(CASE WHEN a.MeetingType='2' AND a.Attend='Y' THEN 1 END) FROM WM1 a WHERE a.ACCOUNT=t.ACCOUNT AND a.CreatedUnit=t.UnitCode) MEETING_TIMES
/*--是否繳交教學自我審核報告 objSheet.Column(30).Width = 10; REPORTREC_YN*/
,(SELECT COUNT(CASE WHEN a.AuditStatus='Y' THEN 1 END) FROM SelfReport a WHERE a.TeacherAccount=t.ACCOUNT AND a.UnitCode=t.UnitCode AND a.[Year]=t.YEARS) REPORTREC_YN_CNT
/*--評核各項指標結果 objSheet.Column(31).Width = 10; POINT_RESULTS*/
/*--前一年度情形 objSheet.Column(32).Width = 10; PYEARS_STATUS*/
/*--評核結果 objSheet.Column(33).Width = 10; REVIEW_RESULTS*/
FROM WT1 t
